[Fact]
public async Task GetArticles_ReturnsOk_WithListOfArticles()
{
    // Arrange
    var mockRepo = new Mock<IArticleRepository>();
    var articles = new List<Article>
    {
        new Article { Id = 1, Titre = "A" },
        new Article { Id = 2, Titre = "B" }
    };
    mockRepo.Setup(r => r.GetAllAsync()).ReturnsAsync(articles);
    var controller = new ArticlesController(mockRepo.Object);

    // Act
    var result = await controller.GetArticles();

    // Assert
    var okResult = Assert.IsType<OkObjectResult>(result.Result);
    var returnedArticles = Assert.IsType<List<Article>>(okResult.Value);
    Assert.Equal(2, returnedArticles.Count);
}
